class Session {
public:
    Session(int userId) : userId(userId), lastAccessed(std::chrono::system_clock::now()) {}
    
    int getUserId() const { return userId; }
    void updateLastAccessed() { lastAccessed = std::chrono::system_clock::now(); }
    
private:
    int userId;
    std::chrono::time_point<std::chrono::system_clock> lastAccessed;
};

class SessionCache {
public:
    void createSession(int sessionId, int userId) {
        if (sessions.find(sessionId) == sessions.end()) {
            sessions[sessionId] = std::make_shared<Session>(userId);
            std::cout << "Session created for user: " << userId << std::endl;
        } else {
            std::cout << "Session already exists for user: " << userId << std::endl;
        }
    }

    int accessSession(int sessionId) {
        auto it = sessions.find(sessionId);
        if (it != sessions.end()) {
            it->second->updateLastAccessed();
            return it->second->getUserId();
        }
        std::cout << "Session not found" << std::endl;
        return -1;
    }

    void invalidateSession(int sessionId) {
        auto it = sessions.find(sessionId);
        if (it != sessions.end()) {
            sessions.erase(it);
            std::cout << "Session invalidated" << std::endl;
        } else {
            std::cout << "Session not found" << std::endl;
        }
    }

private:
    std::unordered_map<int, std::shared_ptr<Session>> sessions;
};

